@import 'default';div.marpit > svg > foreignObject > section {
  width: 1280px;
  height: 720px;

  box-sizing: border-box;
  overflow: hidden;
  position: relative;

  scroll-snap-align: center center;

  -webkit-text-size-adjust: 100%;
  text-size-adjust: 100%;
}div.marpit > svg > foreignObject > section::after {
  bottom: 0;
  content: attr(data-marpit-pagination);
  padding: inherit;
  pointer-events: none;
  position: absolute;
  right: 0;
}div.marpit > svg > foreignObject > section:not([data-marpit-pagination])::after {
  display: none;
}/* Normalization */div.marpit > svg > foreignObject > section h1 {
  font-size: 2em;
  margin-block: 0.67em;
}div.marpit > svg > foreignObject > section video::-webkit-media-controls {
  will-change: transform;
}@page {
  size: 1280px 720px;
  margin: 0;
}@media print {html, body {
  background-color: #fff;
  margin: 0;
  page-break-inside: avoid;
  break-inside: avoid-page;
}
  div.marpit > svg > foreignObject > section {
    page-break-before: always;
    break-before: page;
  }

  div.marpit > svg > foreignObject > section, div.marpit > svg > foreignObject > section * {
    -webkit-print-color-adjust: exact !important;
    animation-delay: 0s !important;
    animation-duration: 0s !important;
    color-adjust: exact !important;
    print-color-adjust: exact !important;
    transition: none !important;
  }

  div.marpit > svg[data-marpit-svg] {
    display: block;
    height: 100vh;
    width: 100vw;
  }
}

/* @theme custom */

div.marpit > svg > foreignObject > :where(section):not([\20 root]) {
  --primary-color: #4a86e8;
  --secondary-color: #ff9900;
  --background-color: #f5f5f5;
  --text-color: #333333;
}

div.marpit > svg > foreignObject > section {
  background-color: var(--background-color);
  color: var(--text-color);
  font-family: 'Arial', sans-serif;
  font-size: 36px;
  line-height: 1.5;
  padding: 40px;
}

div.marpit > svg > foreignObject > section {
  --marpit-root-font-size: 36px;
}

div.marpit > svg > foreignObject > section h1 {
  color: var(--primary-color);
  border-bottom: 2px solid var(--secondary-color);
  padding-bottom: 15px;
  font-size: 48px;
  margin-bottom: 30px;
}

div.marpit > svg > foreignObject > section h2 {
  font-size: 40px;
  margin-top: 30px;
  margin-bottom: 20px;
}

div.marpit > svg > foreignObject > section ul,
div.marpit > svg > foreignObject > section ol {
  margin-left: 1em;
  margin-bottom: 20px;
  padding-left: 1em;
}

div.marpit > svg > foreignObject > section li {
  margin-bottom: 10px;
  padding-left: 0.5em;
}

/* 番号付きリストのスタイリング改善 */
div.marpit > svg > foreignObject > section ol {
  list-style-type: decimal;
  counter-reset: list;
}

div.marpit > svg > foreignObject > section ol > li {
  list-style-type: none;
  position: relative;
}

div.marpit > svg > foreignObject > section ol > li::before {
  counter-increment: list;
  content: counter(list) '.';
  position: absolute;
  left: -1.5em;
  width: 1.5em;
  text-align: right;
}

/* 箇条書きリストのスタイリング改善 */
div.marpit > svg > foreignObject > section ul {
  list-style-type: disc;
}

div.marpit > svg > foreignObject > section ul > li {
  list-style-type: none;
  position: relative;
}

div.marpit > svg > foreignObject > section ul > li::before {
  content: '•';
  position: absolute;
  left: -1em;
  width: 1em;
  text-align: center;
}

/* ネストされたリストのスタイリング */
div.marpit > svg > foreignObject > section ol ol,
div.marpit > svg > foreignObject > section ul ul,
div.marpit > svg > foreignObject > section ol ul,
div.marpit > svg > foreignObject > section ul ol {
  margin-top: 10px;
  margin-bottom: 0;
  margin-left: 1em;
}

div.marpit > svg > foreignObject > section img {
  border-radius: 10px;
  max-width: 90%;
  height: auto;
}

div.marpit > svg > foreignObject > section .columns {
  display: flex;
  gap: calc(var(--marpit-root-font-size, 1rem) * 1);
}

div.marpit > svg > foreignObject > section .columns > div {
  flex: 1;
}

div.marpit > svg > foreignObject > section .columns img {
  max-width: 100%;
  height: auto;
}

div.marpit > svg > foreignObject > section.title {
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  height: 100%;
}

div.marpit > svg > foreignObject > section.title h1 {
  font-size: 64px;
  text-align: center;
  border: none;
}

div.marpit > svg > foreignObject > section.end {
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  height: 100%;
}

div.marpit > svg > foreignObject > section.end h1 {
  font-size: 56px;
  text-align: center;
}

/* ページ番号のスタイル */
div.marpit > svg > foreignObject > section::after {
  content: attr(data-marpit-pagination) '/' attr(data-marpit-pagination-total);
  font-size: 18px;
  color: var(--text-color);
  opacity: 0.5;
  right: 30px;
  bottom: 20px;
}
div.marpit > svg > foreignObject > section::after {
  --marpit-root-font-size: 18px;
}
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="background"] {
  columns: initial !important;
  display: block !important;
  padding: 0 !important;
}
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="background"]::before,
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="background"]::after,
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="content"]::before,
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="content"]::after {
  display: none !important;
}
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="background"] > div[data-marpit-advanced-background-container] {
  all: initial;
  display: flex;
  flex-direction: row;
  height: 100%;
  overflow: hidden;
  width: 100%;
}
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="background"] > div[data-marpit-advanced-background-container][data-marpit-advanced-background-direction="vertical"] {
  flex-direction: column;
}
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="background"][data-marpit-advanced-background-split] > div[data-marpit-advanced-background-container] {
  width: var(--marpit-advanced-background-split, 50%);
}
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="background"][data-marpit-advanced-background-split="right"] > div[data-marpit-advanced-background-container] {
  margin-left: calc(100% - var(--marpit-advanced-background-split, 50%));
}
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="background"] > div[data-marpit-advanced-background-container] > figure {
  all: initial;
  background-position: center;
  background-repeat: no-repeat;
  background-size: cover;
  flex: auto;
  margin: 0;
}
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="background"] > div[data-marpit-advanced-background-container] > figure > figcaption {
	position: absolute;
  border: 0;
  clip: rect(0, 0, 0, 0);
  height: 1px;
  margin: -1px;
  overflow: hidden;
  padding: 0;
  white-space: nowrap;
  width: 1px;
}
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="content"],
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="pseudo"] {
  background: transparent !important;
}
div.marpit > svg > foreignObject > section[data-marpit-advanced-background="pseudo"],
div.marpit > svg[data-marpit-svg] > foreignObject[data-marpit-advanced-background="pseudo"] {
  pointer-events: none !important;
}
div.marpit > svg > foreignObject > section[data-marpit-advanced-background-split] {
  width: 100%;
  height: 100%;
}
